sql:
SELECT COUNT(*) AS accident_count
FROM accidents
WHERE year = 2020;

external_knowledge:
- "stormy events" refers to accidents with a severity level of 2 or higher;
- "top 5 most stormy events" means the top 5 accidents ranked by severity each year;
- "names and traits" include the year, accident ID, severity, number of vehicles, road configuration, weather condition, road surface, and road alignment.

- 'shaken the ground' symbolizes severe accidents significantly impacting the area;
- 'stormy tales' and 'tempest of vehicles' are metaphorical expressions for major accidents with high vehicle involvement;
- 'identity of the collisions' refers to the accident ID;
- 'intensity' refers to the severity level of the accidents;
- 'nature of the road underfoot' refers to the road surface conditions;
- 'commands controlling the chaos' refer to the traffic controls;
- 'weather adding fuel to the fire' refers to the weather conditions contributing to the severity of the accidents.

sql:
SELECT month, AVG(num_vehicles) AS avg_vehicles
FROM accidents
GROUP BY month;

SELECT accident_id, severity
FROM accidents
ORDER BY severity DESC;

SELECT COUNT(DISTINCT accident_id) AS total_accidents
FROM accidents
WHERE year = 2023 AND month = 10;

SELECT DISTINCT rc.road_config_name
FROM accidents a
JOIN road_configs rc ON a.road_config_id = rc.road_config_id;

SELECT COUNT(*) AS total_severe_accidents
FROM accidents
WHERE severity = 2 AND year = 2023 AND month = 10;
